<?php
if (!function_exists('hr_t')) {
  function hr_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('hr_h')) {
  function hr_h($key, $fallback = '') { return htmlspecialchars((string) hr_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('hr_js')) {
  function hr_js($key, $fallback = '') { return json_encode(hr_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
if (session_status() === PHP_SESSION_NONE) session_start();
include "../../inc/config.php";
session_check_json();
function hcd_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
function hcd_label($s){$map=array('DRAFT'=>'warning','ACTIVE'=>'success','INACTIVE'=>'default');$c=isset($map[$s])?$map[$s]:'default';return '<span class="label label-'.$c.'">'.hcd_h($s).'</span>';}
$draw=isset($_POST['draw'])?(int)$_POST['draw']:1;$start=isset($_POST['start'])?max(0,(int)$_POST['start']):0;$length=isset($_POST['length'])?(int)$_POST['length']:25;if($length<=0||$length>500)$length=25;
$from=isset($_POST['tgl_awal'])&&$_POST['tgl_awal']!==''?$_POST['tgl_awal']:date('Y-01-01');$to=isset($_POST['tgl_akhir'])&&$_POST['tgl_akhir']!==''?$_POST['tgl_akhir']:date('Y-12-31');$type=isset($_POST['holiday_type'])?trim($_POST['holiday_type']):'';$scope=isset($_POST['holiday_scope'])?trim($_POST['holiday_scope']):'';$status=isset($_POST['holiday_status'])?trim($_POST['holiday_status']):'';$cal=isset($_POST['calendar_id'])?trim($_POST['calendar_id']):'';$kw=isset($_POST['keyword'])?trim($_POST['keyword']):'';
$w=" WHERE hc.holiday_date<=? AND COALESCE(hc.holiday_end_date,hc.holiday_date)>=? ";$p=array($to,$from);if($type!==''){$w.=" AND hc.holiday_type=? ";$p[]=$type;}if($scope!==''){$w.=" AND hc.holiday_scope=? ";$p[]=$scope;}if($status!==''){$w.=" AND hc.holiday_status=? ";$p[]=$status;}if($cal!==''){$w.=" AND hc.calendar_id=? ";$p[]=(int)$cal;}if($kw!==''){$like='%'.$kw.'%';$w.=" AND (hc.holiday_code LIKE ? OR hc.holiday_name LIKE ? OR hc.region_code LIKE ? OR hc.source_reference LIKE ? OR hc.sap_reference LIKE ?) ";array_push($p,$like,$like,$like,$like,$like);}
$kpi=$db->fetch("SELECT COUNT(*) total,SUM(holiday_status='ACTIVE') active,SUM(holiday_type='PUBLIC_HOLIDAY') public_holiday,SUM(holiday_type='COLLECTIVE_LEAVE') collective_leave,SUM(holiday_type='HALF_DAY') half_day FROM erp_holiday_calendar");
$cnt=$db->fetch("SELECT COUNT(*) jml FROM erp_holiday_calendar hc $w",$p);$total=$cnt?(int)$cnt->jml:0;
$orderMap=array(2=>'hc.holiday_code',3=>'hc.holiday_date',4=>'hc.holiday_type',5=>'hc.holiday_scope',6=>'hc.calendar_code',7=>'hc.working_hours',8=>'hc.holiday_status',9=>'hc.updated_at');$orderBy='hc.holiday_date,hc.holiday_code';if(isset($_POST['order'][0]['column'])){$col=(int)$_POST['order'][0]['column'];$dir=(isset($_POST['order'][0]['dir'])&&strtolower($_POST['order'][0]['dir'])==='desc')?'DESC':'ASC';if(isset($orderMap[$col]))$orderBy=$orderMap[$col].' '.$dir;}
$rows=$db->query("SELECT hc.*,fc.calendar_name,wl.location_code,wl.location_name FROM erp_holiday_calendar hc LEFT JOIN erp_factory_calendar_header fc ON fc.id=hc.calendar_id LEFT JOIN erp_work_location wl ON wl.id=hc.work_location_id $w ORDER BY $orderBy LIMIT $start,$length",$p);
$data=array();$no=$start+1;foreach($rows as $r){$canDel=$r->holiday_status==='ACTIVE'?' disabled':'';$next=$r->holiday_status==='ACTIVE'?'INACTIVE':'ACTIVE';$act='<div class="hc-action"><button class="btn btn-info btn-xs btn-hc-detail" data-id="'.(int)$r->id.'" title="'.hr_h('common_detail', 'Detail').'"><i class="fa fa-eye"></i></button> <button class="btn btn-primary btn-xs btn-hc-edit" data-id="'.(int)$r->id.'" title="'.hr_h('common_edit', 'Edit').'"><i class="fa fa-pencil"></i></button> <button class="btn btn-success btn-xs btn-hc-apply" data-id="'.(int)$r->id.'" title="Apply Calendar"><i class="fa fa-calendar-check-o"></i></button> <button class="btn btn-warning btn-xs btn-hc-status" data-id="'.(int)$r->id.'" data-status="'.$next.'" title="'.$next.'"><i class="fa fa-refresh"></i></button> <button class="btn btn-danger btn-xs btn-hc-delete" data-id="'.(int)$r->id.'" data-no="'.hcd_h($r->holiday_code).'" title="'.hr_h('common_delete', 'Delete').'"'.$canDel.'><i class="fa fa-trash"></i></button></div>';
  $data[]=array($no++,$act,'<strong>'.hcd_h($r->holiday_code).'</strong><br><small>'.hcd_h($r->holiday_name).'</small>','<strong>'.hcd_h($r->holiday_date).'</strong><br><small>s/d '.hcd_h($r->holiday_end_date).'</small>','<strong>'.hcd_h($r->holiday_type).'</strong><br><small>'.hcd_h($r->source_reference?:'-').'</small>','<strong>'.hcd_h($r->holiday_scope).'</strong><br><small>'.hcd_h(($r->region_code?:'-').' / '.$r->country).'</small>','<strong>'.hcd_h($r->calendar_code?:'-').'</strong><br><small>'.hcd_h($r->calendar_name?:'-').'</small>','<strong>'.hcd_h($r->working_hours).'</strong><br><small>Paid '.hcd_h($r->paid_holiday).' | Rec '.hcd_h($r->recurring_annual).'</small>',hcd_label($r->holiday_status),hcd_h($r->updated_by?:$r->created_by?:'-').'<br><small>'.hcd_h($r->updated_at?:$r->created_at).'</small>');}
header('Content-Type: application/json; charset=utf-8');echo json_encode(array('draw'=>$draw,'recordsTotal'=>$total,'recordsFiltered'=>$total,'data'=>$data,'kpi'=>array('total'=>$kpi?(int)$kpi->total:0,'active'=>$kpi?(int)$kpi->active:0,'public_holiday'=>$kpi?(int)$kpi->public_holiday:0,'collective_leave'=>$kpi?(int)$kpi->collective_leave:0,'half_day'=>$kpi?(int)$kpi->half_day:0)));
?>
